option.value:
.detalle-page {
    padding: 140px 20px 60px;
    background-color: #f8fafc;
    min-height: 100vh;
}

.detalle-card {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 50px;
    background: white;
    padding: 40px;
    border-radius: 20px;
    box-shadow: 0 10px 25px rgba(0,0,0,0.05);
}

.detalle-img img {
    width: 100%;
    border-radius: 15px;
    object-fit: contain;
}

.tag-original {
    background: #dcfce7;
    color: #166534;
    padding: 5px 15px;
    border-radius: 50px;
    font-weight: bold;
    font-size: 0.8rem;
}

.detalle-info h1 {
    font-size: 2.5rem;
    color: #1a2f6e;
    margin: 20px 0;
}

.specs-container {
    display: flex;
    flex-direction: column;
    gap: 15px;
    margin: 30px 0;
}

.spec-box {
    display: flex;
    align-items: center;
    gap: 12px;
    font-size: 1.1rem;
    color: #475569;
}

.spec-box svg { color: #00aaff; }

.btn-cotizar {
    background: #1a2f6e;
    color: white;
    padding: 15px 40px;
    border-radius: 10px;
    border: none;
    font-weight: bold;
    cursor: pointer;
    transition: 0.3s;
}

.btn-cotizar:hover { background: #00aaff; }

.detalle-page {
    padding: 120px 20px 60px;
    background-color: #f8fafc;
    min-height: 100vh;
}

.back-btn {
    display: inline-flex;
    align-items: center;
    gap: 8px;
    background: none;
    border: none;
    color: #334155;
    font-size: 1rem;
    margin-bottom: 20px;
    cursor: pointer;
}

.detalle-main-content {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 50px;
    background: white;
    padding: 40px;
    border-radius: 20px;
    box-shadow: 0 10px 25px rgba(0,0,0,0.05);
    align-items: flex-start;
}

.detalle-img img {
    width: 100%;
    border-radius: 15px;
    border: 1px solid #e2e8f0;
}

.detalle-header-info {
    display: flex;
    flex-direction: column;
}

.tag-original {
    background: #dcfce7;
    color: #166534;
    padding: 5px 15px;
    border-radius: 50px;
    font-weight: bold;
    font-size: 0.8rem;
    align-self: flex-start;
}

.detalle-header-info h1 {
    font-size: 2.2rem;
    color: #1a2f6e;
    margin: 15px 0;
}

.detalle-descripcion {
    color: #475569;
    line-height: 1.6;
    margin-bottom: 25px;
}

.action-area {
    margin-top: auto;
    background-color: #f1f5f9;
    padding: 20px;
    border-radius: 10px;
}

.price-tag {
    font-size: 1.5rem;
    font-weight: bold;
    color: #1a2f6e;
    margin: 0 0 15px 0;
}

.btn-cotizar {
    background: #1a2f6e;
    color: white;
    width: 100%;
    padding: 15px;
    border-radius: 10px;
    border: none;
    font-weight: bold;
    font-size: 1rem;
    cursor: pointer;
    transition: 0.3s;
}

.btn-cotizar:hover { background: #00aaff; }

.detalle-additional-info {
    margin-top: 40px;
    background: white;
    padding: 30px 40px;
    border-radius: 20px;
    box-shadow: 0 10px 25px rgba(0,0,0,0.05);
}

.detalle-additional-info h2 {
    font-size: 1.5rem;
    color: #1a2f6e;
    margin-bottom: 20px;
    padding-bottom: 15px;
    border-bottom: 1px solid #e2e8f0;
}

.specs-grid {
    display: grid;
    grid-template-columns: 1fr;
    gap: 15px;
}

.spec-item {
    display: grid;
    grid-template-columns: 200px 1fr;
    padding: 15px 0;
    border-bottom: 1px solid #f1f5f9;
}

.spec-item:last-child {
    border-bottom: none;
}

.spec-item span {
    color: #64748b;
}

.spec-item strong {
    color: #334155;
    font-weight: 600;
}
